def last_n(n, seq):
    """ The final n elements of a sequence

    >>> last_n(2, [10, 20, 30, 40, 50])
    [40, 50]

    See Also:
        skip_n
        first_n
    """
    try:
        return seq[-n:]
    except (TypeError, KeyError):
        return tuple(collections.deque(seq, n))

