def without_keys(d, *keys, **kwargs):
    """ Return a new dict with the given key(s) removed.

    New dict has d[key] deleted for each supplied key.
    Does not modify the initial dictionary.

    >>> without_keys({'x': 1, 'y': 2}, 'y')
    {'x': 1}
    >>> without_keys({'x': 1, 'y': 2}, 'y', 'x')
    {}
    >>> without_keys({'x': 1}, 'y') # Ignores missing keys
    {'x': 1}
    """
    factory = _get_factory(without_keys, kwargs)
    d2 = factory()

    if len(keys) < len(d) * .6:
        d2.update(d)
        for key in keys:
            if key in d2:
                del d2[key]
    else:
        remaining = set(d)
        remaining.difference_update(keys)
        for k in remaining:
            d2[k] = d[k]
    return d2

def combine_dicts_with(func, *dicts, **kwargs):
    """ Merge dictionaries and invoke_with function to combined values

    A key may occur in more than one dict, and all values mapped from the key
    will be passed to the function as a list, such as func([val1, val2, ...]).

    >>> combine_dicts_with(sum, {1: 1, 2: 2}, {1: 10, 2: 20})
    {1: 11, 2: 22}

    >>> combine_dicts_with(head, {1: 1, 2: 2}, {2: 20, 3: 30})  # doctest: +SKIP
    {1: 1, 2: 2, 3: 30}

    See Also:
        combine_dicts
    """
    if len(dicts) == 1 and not isinstance(dicts[0], Mapping):
        dicts = dicts[0]
    factory = _get_factory(combine_dicts_with, kwargs)

    values = collections.defaultdict(lambda: [].append)
    for d in dicts:
        for k, v in d.items():
            values[k](v)

    result = factory()
    for k, v in values.items():
        result[k] = func(v.__self__)
    return result

def head(seq):
    """ The head element in a sequence

    >>> head('ABC')
    'A'
    """
    return next(iter(seq))

